    handleAvailableSelect = (selectionInfo) => {
        //console.log(selectionInfo)


        var availableEventsFilter = this.state.availableEvents.filter(Record => Moment(Record.start).format("YYYY-MM-DD") === Moment(selectionInfo.start).format("YYYY-MM-DD"))


        var foundOverlap = false

        var startTime = Moment(Moment(selectionInfo.start).format("YYYY-MM-DD") + "T" + Moment(selectionInfo.start).format("HH:mm:ss"))
        var endTime = Moment(Moment(selectionInfo.end).format("YYYY-MM-DD") + "T" + Moment(selectionInfo.end).format("HH:mm:ss"))


        var availableSelectedDate = Moment(selectionInfo.start).format("YYYY-MM-DD")
        //this.setState({availableSelectedDate: availableSelectedDate})

        for(var index in availableEventsFilter) {
            var eventStartTime = Moment(availableEventsFilter[index].start)
            var eventEndTime = Moment(availableEventsFilter[index].end)
            if (startTime >= eventStartTime && startTime < eventEndTime) {
                foundOverlap = true
            }
            if (endTime > eventStartTime && endTime <= eventEndTime) {
                foundOverlap = true
            }
            if (eventStartTime >= startTime && eventStartTime < endTime) {
                foundOverlap = true
            }
            if (eventEndTime > startTime && eventEndTime <= endTime) {
                foundOverlap = true
            }
        }


        if (!foundOverlap) {
            this.setState({showAvailableSelect: true})
            this.setState({availableSelectedStart: startTime})
            this.setState({availableSelectedEnd: endTime})
            this.setState({availableSelectedDate: availableSelectedDate})
        } else {
            alert("The selected time has been setted")
            this.setState({showAvailableSelect: false})
        }



    }


    handleCancelReservation = (event) => {


