                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelSetAvailable()}  id="cancelBooking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleSetAvailable()}  id="booking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


                manageSpace.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",width:"800px",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
                window.scrollTo(0, 0)

              }



              manageSpace.push(<div style={{color:"red", marginBottom: "10px"}}>*** please select available time below for other to book your space ***</div>)
              manageSpace.push( <FullCalendar
                plugins={[interactionPlugin, timeGridPlugin ]}
                initialView="timeGridWeek"
                slotMinTime={this.slotMinTime}
                slotMaxTime={this.slotMaxTime}
                height="670px"
                allDaySlot={false}
                //initialDate={new Date(this.state.selectedDate)}
                //headerToolbar={{right: ""}}
                selectable={true}
                events={this.state.availableEvents}
                select={e => this.handleAvailableSelect(e)}
                //selectOverlap={function(event) {return event.rendering === 'background'}}

                //eventClick={this.handleEventClick}
                //dateClick={this.handleDateClick}
                //eventOrder="id"
                //eventDidMount={this.handleDidMount}
                //initialDate= {this.state.setCalendarDate}
                //eventsSet={this.handleEvents}
                //navLinkDayClick={this.handleLinkClick}

              />)




              var tabContent = []


              var tabInside = []

              tabInside.push(<Tab>Your Reservation</Tab>)
              tabInside.push(<Tab>Find Available Space</Tab>)

              var tabInside2 = []
              tabInside2.push(<TabPanel><h2>Your Reservation</h2><div>{yourSpace}</div></TabPanel>)
              tabInside2.push(<TabPanel><h2>Find Available Space</h2><div style={{display: "flex"}}><div style={{marginRight: "50px", width: "400px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div></TabPanel>)

              if (this.state.showManageSpace) {
                tabInside.push(<Tab>Manage Your Space</Tab>)
                tabInside2.push(<TabPanel><h2>Manager Your Space ({this.state.yourRoomName})</h2><div >{manageSpace}</div></TabPanel>)
              }



              tabContent.push(<Tabs>
                  <TabList>
                      {tabInside}
                  </TabList>
                {tabInside2}

              </Tabs>)

            content.push(tabContent)




          }



            return (




<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}

</div>

            );
          }


  };

  export default Room
